<?php require_once __DIR__ . '/../vendor/autoload.php'; $em = require __DIR__ . '/../cli-config.php'; $conn = $em->getConnection(); try { $adminId = $conn->executeQuery('SELECT id FROM users WHERE role = ''ADMIN'' LIMIT 1')->fetchOne(); if ($adminId) { $conn->executeStatement('UPDATE admin_activity_logs SET admin_id = ?', [$adminId]); echo 'Fixed admin_id to ' . $adminId; } else { echo 'No admin found'; } } catch (Exception $e) { echo $e->getMessage(); }
